import React, { useState, useEffect } from "react";
import axios from "axios";

import Layout from "../components/Layout";

import {
    Typography,
    Card,
    CardContent,
    TextField,
    Button,
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableRow,
    Grid
} from "@mui/material";

function Devices() {

    const [deviceName, setDeviceName] = useState("");
    const [deviceType, setDeviceType] = useState("");
    const [imei, setImei] = useState("");
    const [location, setLocation] = useState("");

    const [devices, setDevices] = useState([]);

    useEffect(() => {
        axios
            .get("http://localhost:8080/devices")
            .then((res) => {
                setDevices(res.data);
            })
            .catch((err) => {
                console.error(err);
            });
    }, []);

    const addDevice = () => {
        alert("Backend POST API will be added next");
    };

    const deleteDevice = (id) => {
        alert("Backend DELETE API will be added next");
    };

    const changeStatus = (id) => {
        alert("Status API will be added next");
    };

    return (
        <Layout>

            <Typography variant="h4" gutterBottom>
                IoT Device DB Management
            </Typography>

            <Typography
                variant="subtitle1"
                color="primary"
            >
                Device Registration • Inventory • Lifecycle Management
            </Typography>

            <Typography
                variant="body2"
                color="text.secondary"
                sx={{ mb: 4 }}
            >
                Create, monitor, update and manage connected
                IoT devices across the 5G AF platform.
            </Typography>

            <Card sx={{ mb: 3 }}>
                <CardContent>

                    <Typography variant="h6">
                        Add New IoT Device
                    </Typography>

                    <br />

                    <Grid container spacing={2}>

                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="Device Name"
                                value={deviceName}
                                onChange={(e) =>
                                    setDeviceName(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={2}>
                            <TextField
                                fullWidth
                                label="Type"
                                value={deviceType}
                                onChange={(e) =>
                                    setDeviceType(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={3}>
                            <TextField
                                fullWidth
                                label="IMEI"
                                value={imei}
                                onChange={(e) =>
                                    setImei(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={2}>
                            <TextField
                                fullWidth
                                label="Location"
                                value={location}
                                onChange={(e) =>
                                    setLocation(e.target.value)
                                }
                            />
                        </Grid>

                        <Grid item xs={12} md={2}>
                            <Button
                                fullWidth
                                variant="contained"
                                sx={{ height: "56px" }}
                                onClick={addDevice}
                            >
                                Add
                            </Button>
                        </Grid>

                    </Grid>

                </CardContent>
            </Card>

            <Card>
                <CardContent>

                    <Typography variant="h6">
                        IoT Device Database
                    </Typography>

                    <br />

                    <Table>

                        <TableHead>

                            <TableRow>

                                <TableCell><b>ID</b></TableCell>
                                <TableCell><b>Name</b></TableCell>
                                <TableCell><b>Type</b></TableCell>
                                <TableCell><b>IMEI</b></TableCell>
                                <TableCell><b>Status</b></TableCell>
                                <TableCell><b>Location</b></TableCell>
                                <TableCell><b>Actions</b></TableCell>

                            </TableRow>

                        </TableHead>

                        <TableBody>

                            {devices.map((device) => (

                                <TableRow key={device.id}>

                                    <TableCell>
                                        {device.id}
                                    </TableCell>

                                    <TableCell>
                                        {device.deviceName}
                                    </TableCell>

                                    <TableCell>
                                        {device.deviceType}
                                    </TableCell>

                                    <TableCell>
                                        {device.imei}
                                    </TableCell>

                                    <TableCell>
                                        {device.status}
                                    </TableCell>

                                    <TableCell>
                                        {device.location}
                                    </TableCell>

                                    <TableCell>

                                        <Button
                                            size="small"
                                            color="warning"
                                            variant="contained"
                                            sx={{ mr: 1 }}
                                            onClick={() =>
                                                changeStatus(device.id)
                                            }
                                        >
                                            Status
                                        </Button>

                                        <Button
                                            size="small"
                                            color="error"
                                            variant="contained"
                                            onClick={() =>
                                                deleteDevice(device.id)
                                            }
                                        >
                                            Delete
                                        </Button>

                                    </TableCell>

                                </TableRow>

                            ))}

                        </TableBody>

                    </Table>

                </CardContent>
            </Card>

        </Layout>
    );
}

export default Devices;
